#include <bits/stdc++.h>
using namespace std;
int n, cnt;
bool v[201005], bk[200105];
vector<int> a[200050];

void dfs(int u, int s) {
	if (v[u]) {
		return;
	}
	if (s % 2 == 0) {
		bk[u] = 1;
		cnt ++;
	}
	v[u] = 1;
	for (int i = 0; i < a[u].size(); i++) {
		dfs(a[u][i], s + 1);
	}
}
int main() {
	cin >> n;
	for (int i = 1; i < n; i++) {
		int b, c;
		cin >> b >> c;
		a[b].push_back(c);
		a[c].push_back(b);
	}
	dfs(1, 0);
	for (int i = 1; i <= n; i++) {
		if (bk[i]) {
			cout << cnt << " ";
		} else {
			cout << n - cnt << " ";
		}
	}
}
